/**
 * Validation helper module.
 * Each function returns an array of human-readable error strings.
 * An empty array means validation passed.
 */

// RFC 5321 / HTML5 email pattern – covers the vast majority of real addresses.
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate a route parameter that must be a whole-number id.
 * @param {*} id  - raw value from req.params
 * @returns {string[]} list of validation errors
 */
function validateId(id) {
  const errors = [];

  if (id === undefined || id === null || id === '') {
    errors.push('id is required');
    return errors; // no point checking further
  }

  // Express gives params as strings; accept only digit-only strings.
  if (!/^\d+$/.test(String(id))) {
    errors.push('id must be a numeric value');
  }

  return errors;
}

/**
 * Validate the user-facing fields (name, email) from a request body.
 *
 * @param {object} body           - req.body
 * @param {object} [options]
 * @param {boolean} [options.requireAll=true]  - when true, missing fields are
 *   an error (POST); when false, missing fields are silently skipped (PATCH).
 * @returns {string[]} list of validation errors
 */
function validateUserBody(body, { requireAll = true } = {}) {
  const errors = [];
  const { name, email } = body || {};

  // ── name ──────────────────────────────────────────────────────────────────
  if (name === undefined || name === null) {
    if (requireAll) {
      errors.push('name is required');
    }
    // else: optional field omitted – nothing to validate
  } else {
    if (typeof name !== 'string') {
      errors.push('name must be a string');
    } else if (name.length < 1) {
      errors.push('name must be at least 1 character long');
    } else if (name.length > 100) {
      errors.push('name must be at most 100 characters long');
    }
  }

  // ── email ─────────────────────────────────────────────────────────────────
  if (email === undefined || email === null) {
    if (requireAll) {
      errors.push('email is required');
    }
  } else {
    if (typeof email !== 'string') {
      errors.push('email must be a string');
    } else if (!EMAIL_REGEX.test(email)) {
      errors.push('email must be a valid email address');
    } else if (email.length > 254) {
      errors.push('email must be at most 254 characters long');
    }
  }

  return errors;
}

/**
 * Convenience: send a 400 response with a structured error payload.
 * Returns false so callers can do: if (sendValidationError(...)) return;
 *
 * @param {import('express').Response} res
 * @param {string[]} errors
 * @returns {boolean} always true (error was sent)
 */
function sendValidationError(res, errors) {
  res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
  return true;
}

module.exports = { validateId, validateUserBody, sendValidationError };

