/**
 * validation.js
 * Reusable input-validation helpers for Express route handlers.
 *
 * Each validator returns an array of human-readable error strings.
 * An empty array means the value is valid.
 *
 * Usage:
 *   const { validateId, validateName, validateEmail, validationError } = require('./validation');
 *
 *   const errors = [
 *     ...validateId(req.params.id),
 *     ...validateName(req.body.name),
 *     ...validateEmail(req.body.email),
 *   ];
 *   if (errors.length) return validationError(res, errors);
 */

'use strict';

// ---------------------------------------------------------------------------
// Individual field validators
// ---------------------------------------------------------------------------

/**
 * Validate a user ID coming from a URL parameter (always a string at first).
 * Rules:
 *   - Must be present / non-empty
 *   - Must consist only of digits (no floats, no negative signs)
 *   - Parsed integer must be > 0
 *
 * @param {*} id - Raw value, typically req.params.id
 * @returns {string[]} Array of error messages (empty = valid)
 */
function validateId(id) {
  const errors = [];

  if (id === undefined || id === null || String(id).trim() === '') {
    errors.push('id is required');
    return errors; // no point running further checks
  }

  const str = String(id).trim();

  if (!/^\d+$/.test(str)) {
    errors.push('id must be a positive integer (numeric characters only)');
    return errors;
  }

  const parsed = parseInt(str, 10);
  if (parsed <= 0) {
    errors.push('id must be greater than 0');
  }

  return errors;
}

/**
 * Validate a "name" field from a request body.
 * Rules:
 *   - Must be present / non-empty after trimming
 *   - Must be a string (not an array, number, object, etc.)
 *   - Length: 1–100 characters (after trimming)
 *
 * @param {*} name - Raw value, typically req.body.name
 * @returns {string[]} Array of error messages (empty = valid)
 */
function validateName(name) {
  const errors = [];

  if (name === undefined || name === null) {
    errors.push('name is required');
    return errors;
  }

  if (typeof name !== 'string') {
    errors.push('name must be a string');
    return errors;
  }

  const trimmed = name.trim();

  if (trimmed.length === 0) {
    errors.push('name must not be blank');
    return errors;
  }

  if (trimmed.length > 100) {
    errors.push(`name must be at most 100 characters (received ${trimmed.length})`);
  }

  return errors;
}

/**
 * Validate an "email" field from a request body.
 * Rules:
 *   - Must be present / non-empty
 *   - Must be a string
 *   - Must match a standard email format (RFC 5321-inspired regex)
 *   - Total length must not exceed 254 characters (RFC 5321 limit)
 *
 * @param {*} email - Raw value, typically req.body.email
 * @returns {string[]} Array of error messages (empty = valid)
 */
function validateEmail(email) {
  const errors = [];

  if (email === undefined || email === null) {
    errors.push('email is required');
    return errors;
  }

  if (typeof email !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  const trimmed = email.trim();

  if (trimmed.length === 0) {
    errors.push('email must not be blank');
    return errors;
  }

  if (trimmed.length > 254) {
    errors.push(`email must be at most 254 characters (received ${trimmed.length})`);
  }

  // Standard email regex: local-part @ domain
  // local-part: alphanumeric + common special chars, max 64 chars
  // domain: labels separated by dots, each label alphanumeric/hyphens
  const EMAIL_RE = /^[^\s@]{1,64}@[^\s@]+\.[^\s@]{2,}$/;
  if (!EMAIL_RE.test(trimmed)) {
    errors.push('email must be a valid email address (e.g. user@example.com)');
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Response helper
// ---------------------------------------------------------------------------

/**
 * Send a 400 Bad Request response with a structured error body that lists
 * every validation failure.
 *
 * @param {import('express').Response} res  - Express response object
 * @param {string[]}                   errors - Non-empty array of error messages
 */
function validationError(res, errors) {
  return res.status(400).json({
    error: 'Validation failed',
    details: errors,
  });
}

// ---------------------------------------------------------------------------
// Exports
// ---------------------------------------------------------------------------

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validationError,
};

