 * Validate an email field.
 * @param {*} value - The value to validate.
 * @param {boolean} required - Whether the field is required.
 * @returns {string[]} Array of validation error messages.
 */
function validateEmail(value, required = true) {
  const errors = [];
  if (value === undefined || value === null) {
    if (required) errors.push('email is required');
    return errors;
  }
  if (typeof value !== 'string') {
    errors.push('email must be a string');
    return errors;
  }
  if (value.length > 254) {
    errors.push('email must be at most 254 characters');
  }
  if (!EMAIL_REGEX.test(value)) {
    errors.push('email must be a valid email address');
  }
  return errors;
}

/**
 * Validate a full user body (create).
 * Both name and email are required.
 * @param {object} body - The parsed request body.
 * @returns {string[]} Aggregated array of validation error messages.
 */
function validateCreateUser(body) {
  if (!body || typeof body !== 'object') {
    return ['request body must be a JSON object'];
  }
  return [
    ...validateName(body.name, true),
    ...validateEmail(body.email, true),
  ];
}

/**
 * Validate a partial user body (update).
 * At least one of name or email must be present; any that are present are validated.
 * @param {object} body - The parsed request body.
 * @returns {string[]} Aggregated array of validation error messages.
 */
function validateUpdateUser(body) {
  if (!body || typeof body !== 'object') {
    return ['request body must be a JSON object'];
  }
  const errors = [];
  const hasName = body.name !== undefined;
  const hasEmail = body.email !== undefined;

  if (!hasName && !hasEmail) {
    errors.push('at least one field (name, email) must be provided for update');
    return errors;
  }
  if (hasName) errors.push(...validateName(body.name, true));
  if (hasEmail) errors.push(...validateEmail(body.email, true));
  return errors;
}

/**
 * Express middleware factory — runs the given validators and sends a 400
 * response with all error messages when any validation fails.
 *
 * @param {...() => string[]} validators - Zero-argument functions that return error arrays.
 * @returns {Function} Express middleware.
 */
function validate(...validators) {
  return (req, res, next) => {
    const errors = validators.flatMap((fn) => fn(req));
    if (errors.length > 0) {
      return res.status(400).json({ errors });
    }
    next();
  };
}

// Convenience pre-built middleware builders:

/** Validate req.params.id */
const validateParamId = () => (req) => validateId(req.params.id);

/** Validate req.body for user creation */
const validateBodyCreate = () => (req) => validateCreateUser(req.body);

/** Validate req.body for user update */
const validateBodyUpdate = () => (req) => validateUpdateUser(req.body);

module.exports = {
  validateId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
  validate,
  validateParamId,
  validateBodyCreate,
  validateBodyUpdate,
};

