// validation.js — reusable input validation helpers and Express middleware

'use strict';

// RFC 5321 / HTML5-style email pattern: local@domain.tld
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

// ---------------------------------------------------------------------------
// Pure validator functions — each returns an array of error strings
// ---------------------------------------------------------------------------

/**
 * Validates that a value is a positive integer (accepts number or numeric string).
 * @param {*}      value     - The value to test (typically from req.params).
 * @param {string} fieldName - Label used in error messages.
 * @returns {string[]} Array of validation error messages (empty = valid).
 */
function validateId(value, fieldName = 'id') {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push(`${fieldName} is required`);
    return errors;
  }

  const num = Number(value);

  if (!Number.isFinite(num) || !Number.isInteger(num) || num <= 0) {
    errors.push(`${fieldName} must be a positive integer`);
  }

  return errors;
}

/**
 * Validates a name value: must be a string, 1–100 characters.
 * @param {*}      value     - The value to test.
 * @param {string} fieldName - Label used in error messages.
 * @param {boolean} required - Whether the field is mandatory.
 * @returns {string[]}
 */
function validateName(value, fieldName = 'name', required = true) {
  const errors = [];

  if (value === undefined || value === null) {
    if (required) errors.push(`${fieldName} is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return errors;
  }

  if (value.length < 1) {
    errors.push(`${fieldName} must be at least 1 character long`);
  }

  if (value.length > 100) {
    errors.push(`${fieldName} must be at most 100 characters long`);
  }

  return errors;
}

/**
 * Validates an email value: must be a string, valid email format, max 254 chars.
 * @param {*}      value     - The value to test.
 * @param {string} fieldName - Label used in error messages.
 * @param {boolean} required - Whether the field is mandatory.
 * @returns {string[]}
 */
function validateEmail(value, fieldName = 'email', required = true) {
  const errors = [];

  if (value === undefined || value === null) {
    if (required) errors.push(`${fieldName} is required`);
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push(`${fieldName} must be a string`);
    return errors;
  }

  if (value.length > 254) {
    errors.push(`${fieldName} must be at most 254 characters long`);
  }

  if (!EMAIL_REGEX.test(value)) {
    errors.push(`${fieldName} must be a valid email address`);
  }

  return errors;
}

// ---------------------------------------------------------------------------
// Composite validators for specific request shapes
// ---------------------------------------------------------------------------

/**
 * Validates the body of a POST /users request.
 * Both `name` and `email` are required.
 * @param {object} body - req.body
 * @returns {string[]}
 */
function validateCreateUser(body) {
  return [
    ...validateName(body.name, 'name', true),
    ...validateEmail(body.email, 'email', true),
  ];
}

/**
 * Validates the body of a PUT /users/:id request.
 * At least one of `name` or `email` must be provided; whichever are present are validated.
 * @param {object} body - req.body
 * @returns {string[]}
 */
function validateUpdateUser(body) {
  const errors = [];
  const hasName = body.name !== undefined;
  const hasEmail = body.email !== undefined;

  if (!hasName && !hasEmail) {
    errors.push('At least one field (name, email) must be provided for update');
    return errors;
  }

  if (hasName) errors.push(...validateName(body.name, 'name', true));
  if (hasEmail) errors.push(...validateEmail(body.email, 'email', true));

  return errors;
}

// ---------------------------------------------------------------------------
// Express middleware factories — call next() on success, send 400 on failure
// ---------------------------------------------------------------------------

/**
 * Middleware: validates that req.params.id is a positive integer.
 * Attach directly before a route handler: router.get('/:id', validateIdParam, handler)
 */
function validateIdParam(req, res, next) {
  const errors = validateId(req.params.id, 'id');
  if (errors.length > 0) {
    return res.status(400).json({ errors });
  }
  next();
}

/**
 * Middleware: validates the request body for POST /users.
 */
function validateCreateUserBody(req, res, next) {
  const errors = validateCreateUser(req.body || {});
  if (errors.length > 0) {
    return res.status(400).json({ errors });
  }
  next();
}

/**
 * Middleware: validates the request body for PUT /users/:id.
 */
function validateUpdateUserBody(req, res, next) {
  const errors = validateUpdateUser(req.body || {});
  if (errors.length > 0) {
    return res.status(400).json({ errors });
  }
  next();
}

module.exports = {
  // Pure validators (useful for unit tests and reuse)
  validateId,
  validateName,
  validateEmail,
  validateCreateUser,
  validateUpdateUser,
  // Express middleware
  validateIdParam,
  validateCreateUserBody,
  validateUpdateUserBody,
};

