 * Validate a user id value (from URL params).
 * Rules: must be present, must be a whole number (no decimals, no NaN).
 *
 * @param {string|number} value  Raw value, typically req.params.id
 * @returns {string[]}           Array of validation error messages
 */
function validateId(value) {
  const errors = [];

  if (value === undefined || value === null || value === '') {
    errors.push('id is required');
    return errors; // further checks are meaningless
  }

  const num = Number(value);
  if (!Number.isInteger(num) || num < 1) {
    errors.push('id must be a positive integer');
  }

  return errors;
}

/**
 * Validate a user name value.
 * Rules: must be present, must be a non-empty string, 1–100 characters.
 *
 * @param {*}       value  Raw value, typically req.body.name
 * @param {boolean} [required=true]  Set false for partial-update endpoints
 * @returns {string[]}
 */
function validateName(value, required = true) {
  const errors = [];

  if (value === undefined || value === null) {
    if (required) errors.push('name is required');
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push('name must be a string');
    return errors;
  }

  const trimmed = value.trim();
  if (trimmed.length < NAME_MIN) {
    errors.push(`name must be at least ${NAME_MIN} character`);
  } else if (trimmed.length > NAME_MAX) {
    errors.push(`name must be at most ${NAME_MAX} characters`);
  }

  return errors;
}

