 * Rules: must be present, must be a string, must match email format,
 *        max 254 characters (RFC 5321).
 *
 * @param {*}       value  Raw value, typically req.body.email
 * @param {boolean} [required=true]  Set false for partial-update endpoints
 * @returns {string[]}
 */
function validateEmail(value, required = true) {
  const errors = [];

  if (value === undefined || value === null) {
    if (required) errors.push('email is required');
    return errors;
  }

  if (typeof value !== 'string') {
    errors.push('email must be a string');
    return errors;
  }

  if (value.length > EMAIL_MAX) {
    errors.push(`email must be at most ${EMAIL_MAX} characters`);
  }

  if (!EMAIL_REGEX.test(value)) {
    errors.push('email must be a valid email address');
  }

  return errors;
}

module.exports = { validateId, validateName, validateEmail };

